mapper.select:
SELECT n.*, t.teacher_name AS publisher_name FROM notice n
LEFT JOIN teacher t ON n.publisher_id = t.teacher_id
WHERE n.is_deleted=0

    AND (n.title LIKE CONCAT('%',#{keyword},'%') OR n.content LIKE CONCAT('%',#{keyword},'%'))


    AND n.type=#{type}

ORDER BY n.top_flag DESC, n.create_time DESC LIMIT #{offset},#{size}

SELECT COUNT(*) FROM notice WHERE is_deleted=0

    AND (title LIKE CONCAT('%',#{keyword},'%') OR content LIKE CONCAT('%',#{keyword},'%'))

AND type=#{type}
